#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long double a,b,c; long long k; scanf("%Lf %Lf %Lf %lld", &a, &b, &c, &k);
        long double s = (a+b+c)/2.0L;
        long double area = sqrtl(s*(s-a)*(s-b)*(s-c));
        long double ans = area * ( (long double)k / (k+1) );
        printf("%.10Lf\n", ans);
    }
    return 0;
}

